x;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === LEGAL PAGE: PRIVACY POLICY === */\n/* Divi section-level overrides for legal pages */\n.et_pb_section { padding: 0 !important; min-height: auto !important; margin: 0 !important; text-align: start !important; }\n.et_pb_section .et_pb_row { max-width: 100% !important; width: 100% !important; padding: 0 !important; margin: 0 auto !important; }\n.et_pb_section .et_pb_column { padding: 0 !important; }\n.et_pb_section, .et_pb_section * { -webkit-font-smoothing: auto !important; -moz-osx-font-smoothing: auto !important; }\n.et_pb_section p { padding-bottom: 0 !important; }\n.fade-in { opacity: 1 !important; transform: none !important; }\n:root { --dw-blue-text: #0369a1; --dw-gray-light: #F5F7FA; --dw-navy: #000864; }\n\n.dw-section {\n    padding: 100px 80px;\n}\n.dw-section--white {\n    background: #ffffff;\n}\n.dw-section--gray {\n    background: #F5F7FA;\n}\n.dw-section--dark {\n    background: linear-gradient(135deg, #000864 0%, #1e3a5f 100%);\n    color: #ffffff;\n}\n.dw-section--blue {\n    background: linear-gradient(135deg, #00AFF0 0%, #0ea5e9 50%, #0284c7 100%);\n    color: #ffffff;\n    position: relative;\n}\n.dw-section--blue::before {\n    content: \'\';\n    position: absolute;\n    top: 0;\n    left: 0;\n    right: 0;\n    bottom: 0;\n    background: radial-gradient(ellipse at 20% 30%, rgba(255,255,255,0.15) 0%, transparent 50%);\n    pointer-events: none;\n}\n.dw-container {\n    max-width: 1200px;\n    margin: 0 auto;\n}\n    .dw-section {\n        padding: 60px 40px;\n    }\n    .dw-section {\n        padding: 48px 24px;\n    }\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Privacy Policy: Content"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Privacy Policy: Content: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Privacy Policy: Content: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><!-- Content -->\n    <section class="dw-section" style="padding-top: 120px;">\n        <div class="dw-container">\n            <div style="max-width: 800px; margin: 0 auto;">\n                <h1 style="font-family: \'Noto Sans\', sans-serif; font-size: 36px; color: #000864; margin-bottom: 16px;">Privacy Policy</h1>\n                <p style="color: #5b6b80; margin-bottom: 48px;">Last updated: February 2026</p>\n\n                <div style="font-family: \'Noto Sans\', sans-serif; font-size: 16px; line-height: 1.8; color: #000864;">\n                    <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 24px; margin: 32px 0 16px 0;">1. Information We Collect</h2>\n                    <p>DigiWin Thailand ("we," "our," or "us") collects information you provide directly to us, such as when you get in touch, contact us, or apply to become a partner. This may include:</p>\n                    <ul style="margin: 16px 0; padding-left: 24px;">\n                        <li>Name and contact information</li>\n                        <li>Company name and job title</li>\n                        <li>Email address and phone number</li>\n                        <li>Information about your manufacturing operations</li>\n                    </ul>\n\n                    <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 24px; margin: 32px 0 16px 0;">2. How We Use Your Information</h2>\n                    <p>We use the information we collect to:</p>\n                    <ul style="margin: 16px 0; padding-left: 24px;">\n                        <li>Respond to your inquiries and requests</li>\n                        <li>Provide information about our products and services</li>\n                        <li>Process partner applications</li>\n                        <li>Improve our website and services</li>\n                        <li>Send marketing communications (with your consent)</li>\n                    </ul>\n\n                    <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 24px; margin: 32px 0 16px 0;">3. Information Sharing</h2>\n                    <p>We do not sell, trade, or rent your personal information to third parties. We may share your information with:</p>\n                    <ul style="margin: 16px 0; padding-left: 24px;">\n                        <li>DigiWin group companies for business purposes</li>\n                        <li>Service providers who assist our operations</li>\n                        <li>Legal authorities when required by law</li>\n                    </ul>\n\n                    <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 24px; margin: 32px 0 16px 0;">4. Data Security</h2>\n                    <p>We implement appropriate technical and organizational measures to protect your personal information against unauthorized access, alteration, disclosure, or destruction.</p>\n\n                    <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 24px; margin: 32px 0 16px 0;">5. Your Rights</h2>\n                    <p>Under Thailand\'s Personal Data Protection Act (PDPA), you have the right to:</p>\n                    <ul style="margin: 16px 0; padding-left: 24px;">\n                        <li>Access your personal data</li>\n                        <li>Correct inaccurate data</li>\n                        <li>Request deletion of your data</li>\n                        <li>Withdraw consent</li>\n                        <li>Lodge a complaint with authorities</li>\n                    </ul>\n\n                    <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 24px; margin: 32px 0 16px 0;">6. Contact Us</h2>\n                    <p>For questions about this Privacy Policy or to exercise your rights, contact us at:</p>\n                    <p style="margin-top: 16px;">\n                        <strong>DigiWin Thailand</strong><br>\n                        Email: <a href="mailto:info@digiwin.co.th" style="color: #0369a1;">info@digiwin.co.th</a>\n                    </p>\n                </div>\n            </div>\n        </div>\n    </section><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
